const raw = $input.first().json;
const body = raw.body || raw;

let documentContent = '';
let imageBase64 = null;
let documentType = 'unknown';

if (body.document_base64) {
  imageBase64 = body.document_base64;
  documentContent = 'Image document provided';
  documentType = 'image';
} else if (body.document_text) {
  documentContent = body.document_text;
  documentType = 'text';
} else if (body.text) {
  documentContent = body.text;
  documentType = 'text';
} else {
  documentContent = JSON.stringify(body);
  documentType = 'raw';
}

return [{ json: {
  documentContent,
  imageBase64,
  hasImage: !!imageBase64,
  documentType,
  submittedAt: new Date().toISOString(),
  clientIp: raw.headers?.['x-forwarded-for'] || 'unknown'
}}];

const aiResponse = $input.first().json;
const docInfo = $node['Prepare Document'].json;

let result;
try {
  const content = aiResponse.choices[0].message.content;
  const cleaned = content.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  result = JSON.parse(cleaned);
} catch (e) {
  result = {
    document_type: 'PARSE_ERROR',
    is_valid: false,
    tampering_detected: false,
    risk_level: 'HIGH',
    confidence_score: 0,
    flags: ['AI response parse error'],
    verification_notes: 'Manual review required',
    recommended_action: 'REVIEW'
  };
}

result.audit_timestamp = docInfo.submittedAt;
result.document_input_type = docInfo.documentType;

return [{ json: result }];

